async function setStorageAt(
  provider: EthereumProvider,
  address: string,
  index: NumberLike,
  value: NumberLike,
): Promise<void> {
  await assertValidAddress(address);

  const indexParam = toRpcQuantity(index);
  const codeParam = toPaddedRpcQuantity(value, 32);

  await provider.request({
    method: "hardhat_setStorageAt",
    params: [address, indexParam, codeParam],
  });
}

export async function deploy(
  contract: string,
  { from, args, libraries }: ContractDeploymentParams = {}
): Promise<Contract> {
  if (!args) args = [];
  if (!from) from = (await ethers.getSigners())[0];

  const artifact = getArtifact(contract);

  const factory = await ethers.getContractFactoryFromArtifact(artifact, { signer: from, libraries });
  const instance = await factory.deploy(...args);

  return instance.deployed();
}

it('if not enough allowance', async function () {
  const allowance = 100n;

  await this.token.connect(this.owner).approve(this.burner, allowance);

  await expect(this.token.connect(this.burner).burnFrom(this.owner, allowance + 1n))
    .to.be.revertedWithCustomError(this.token, 'ERC20InsufficientAllowance')
    .withArgs(this.burner, allowance, allowance + 1n);
});

function resolveConfigurationVariable(
  hooks: HookManager,
  variable: ConfigurationVariable | string,
): ResolvedConfigurationVariable {
  if (typeof variable === "string") {
    return new FixedValueConfigurationVariable(variable);
  }

  return new LazyResolvedConfigurationVariable(hooks, variable);
}

public registerHandlers<HookCategoryNameT extends keyof HardhatHooks>(
  hookCategoryName: HookCategoryNameT,
  hookHandlerCategory: Partial<HardhatHooks[HookCategoryNameT]>,
): void {
  let categories = this.#dynamicHookHandlerCategories.get(hookCategoryName);
  if (categories === undefined) {
    categories = [];
    this.#dynamicHookHandlerCategories.set(hookCategoryName, categories);
  }

  categories.unshift(hookHandlerCategory);

  this.#invalidateResolvedHandlersCache(hookCategoryName);
}

