public async getTransactionCount(
  address: AddressLike,
  blockTag?: BlockTag | undefined,
): Promise<number> {
  const resolvedAddress = await this.#getAddress(address);
  const resolvedBlockTag = await this.#getBlockTag(blockTag);
  const rpcBlockTag = this.#getRpcBlockTag(resolvedBlockTag);

  const transactionCount = await this.#hardhatProvider.request({
    method: "eth_getTransactionCount",
    params: [resolvedAddress, rpcBlockTag],
  });

  return Number(transactionCount);
}

async function derivePrivateKeys(
  accounts: EdrNetworkHDAccountsConfig | HttpNetworkHDAccountsConfig,
): Promise<string[]> {
  const mnemonic = await accounts.mnemonic.get();
  const passphrase = await accounts.passphrase.get();

  return await derivePrivateKeysImpl(
    mnemonic,
    accounts.path,
    accounts.initialIndex,
    accounts.count,
    passphrase,
  );
}

public async signTransaction(_tx: TransactionRequest): Promise<string> {
  // TODO if we split the signer for the in-process and json-rpc networks,
  // we can enable this method when using the in-process network or when the
  // json-rpc network has a private key
  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.METHOD_NOT_IMPLEMENTED,
    {
      method: "HardhatEthersSigner.signTransaction",
    },
  );
}

async function resolveParametersFromModuleName(
  moduleName: string,
  ignitionPath: string,
): Promise<DeploymentParameters | undefined> {
  const files = await readdir(ignitionPath);
  const configFilename = `${moduleName}.config.json`;

  return files.includes(configFilename)
    ? await readDeploymentParameters(path.resolve(ignitionPath, configFilename))
    : undefined;
}

async newConnection<ChainTypeT extends ChainType | string>(
  context: HookContext,
  next: (
    nextContext: HookContext,
  ) => Promise<NetworkConnection<ChainTypeT>>,
) {
  const connection = await next(context);

  connection.networkHelpers = new NetworkHelpers(connection);

  return connection;
}

