#convertHardhatContractToViemContract(
  connection: NetworkConnection<ChainTypeT>,
  future:
    | NamedArtifactContractDeploymentFuture<string>
    | NamedArtifactLibraryDeploymentFuture<string>
    | NamedArtifactContractAtFuture<string>,
  deployedContract: { address: string },
): Promise<GetContractReturnType> {
  return connection.viem.getContractAt(
    future.contractName,
    ViemIgnitionHelperImpl.#ensureAddressFormat(deployedContract.address),
  );
}

function doesKeyExist({
  masterKey,
  encryptedKeystore,
  key,
}: {
  masterKey: Uint8Array;
  encryptedKeystore: EncryptedKeystore;
  key: string;
}): boolean {
  validateHmac({ masterKey, encryptedKeystore });
  return Object.keys(encryptedKeystore.secrets).includes(key);
}

const { ethers } = require('hardhat');

const selector = signature => ethers.FunctionFragment.from(signature).selector;

const interfaceId = signatures =>
  ethers.toBeHex(
    signatures.reduce((acc, signature) => acc ^ ethers.toBigInt(selector(signature)), 0n),
    4,
  );
